import json
rating_results = locals()['var_functions.query_db:13']
business_results = locals()['var_functions.query_db:6']

business_map = {}
for b in business_results:
    business_map[b['gmap_id']] = b['name']

final_list = []
for r in rating_results:
    if r['gmap_id'] in business_map:
        final_list.append({
            'name': business_map[r['gmap_id']], 
            'avg_rating': float(r['avg_rating'])
        })

final_list.sort(key=lambda x: x['avg_rating'], reverse=True)
top5 = final_list[:5]

out = []
count = 1
for item in top5:
    avg = round(item['avg_rating'], 2)
    out.append(str(count) + '. ' + item['name'] + ': ' + str(avg))
    count = count + 1

print('__RESULT__:')
print(json.dumps('\n'.join(out)))

